unsigned hash_ptr(void *ptr) {
    unsigned h = (uintptr_t) ptr / 16;
    return h;
}


int pointer_equals(void *ptr1, void* ptr2) {
    return ptr1 == ptr2;
}

unsigned hash_string(void *str) {
    unsigned total = 2;
    for (char *reader = str; *reader; ++reader) {
        total += *reader;
        total *= 5;
    }
    return total;
}

