// ============================================================
// Recorre recursivamente el directorio `nom`.  Esta funcion esta
// basada en listDir del programa list-dir.c.  Cada vez que
// encuentra un archivo regular deposita en la cola global un
// puntero a una estructura Archivo con el nombre (copia con
// strdup) y la fecha de modificacion.
// ============================================================
static void recorrer(char *nom) {
